/* The near-universal reset: make width predictable everywhere. */
*, *::before, *::after {
  box-sizing: border-box;
}

.card {
  width: 300px;     /* total rendered width stays 300px with border-box */
  padding: 20px;    /* eats into the content area instead of growing the box */
  border: 1px solid #ccc;
}

.toolbar {
  display: flex;
  align-items: center;            /* vertical centering on the cross axis */
  justify-content: space-between; /* push first/last to the edges */
  gap: 12px;                      /* spacing between items, no margin hacks */
}

.toolbar .spacer { flex: 1; }     /* grows to absorb leftover space */

.search {
  flex: 1 1 200px;  /* grow:1 shrink:1 basis:200px -> flexible but min ~200px */
}

.logo {
  flex: 0 0 auto;   /* never grow or shrink: stays its natural size */
}

/* Responsive card grid: as many columns as fit, each at least 240px,
   sharing leftover space equally. No media queries needed. */
.gallery {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
  gap: 16px;
}

/* Classic app shell with named areas. */
.app {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: auto 1fr auto;
  grid-template-areas:
    'sidebar header'
    'sidebar main'
    'sidebar footer';
  min-height: 100vh;
}
.app > .sidebar { grid-area: sidebar; }
.app > .header  { grid-area: header; }
.app > .main    { grid-area: main; }
.app > .footer  { grid-area: footer; }

/* A common 'z-index does not work' bug. */
.modal { position: fixed; z-index: 1000; }

/* This ancestor accidentally creates a NEW stacking context, so the
   modal inside it can never rise above a sibling of the ancestor,
   no matter how high its z-index. */
.card {
  transform: translateZ(0);   /* creates a stacking context! */
  /* opacity < 1, filter, will-change, position+z-index, isolation:isolate
     and several other properties also create one. */
}

:root {
  /* Custom properties: a single source of truth, themeable at runtime. */
  --space: 1rem;
  --brand: #4f46e5;
}

.title {
  /* Fluid type: scales between 1.5rem and 3rem with the viewport,
     no breakpoint jumps. */
  font-size: clamp(1.5rem, 4vw + 1rem, 3rem);
  color: var(--brand);
}

/* Logical properties adapt to LTR/RTL automatically. */
.note {
  margin-inline-start: var(--space);  /* left in LTR, right in RTL */
  padding-block: var(--space);        /* top and bottom */
}

/* Container queries: style based on the component's own width,
   so the same card adapts inside a sidebar or a wide main column. */
.card-wrapper { container-type: inline-size; }
@container (min-width: 400px) {
  .card { display: grid; grid-template-columns: 120px 1fr; }
}

.row { display: flex; gap: 16px; }
.card { flex: 1; }
.card .title {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;   /* yet it still overflows the row! */
}

.row { display: flex; gap: 16px; }
.card {
  flex: 1;
  min-width: 0;     /* THE FIX: override the default min-width:auto so the
                       card may shrink narrower than its longest word */
}
.card .title {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;   /* now actually truncates */
}

