.card-grid {
  display: grid;
  /* As many 240px-min columns as fit; each flexes up to share free space. */
  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
  gap: 16px;
}

.card {
  /* border-box keeps padding inside the track width */
  box-sizing: border-box;
  padding: 16px;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
}

/* Variant: stretch the last items to fill the row instead of leaving gaps. */
.card-grid--fit {
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
}

/* Backdrop covers the whole viewport and centers its child. */
.modal-backdrop {
  position: fixed;
  inset: 0;                       /* top/right/bottom/left: 0 */
  display: flex;
  align-items: center;            /* vertical centering */
  justify-content: center;        /* horizontal centering */
  background: rgba(0, 0, 0, 0.5);
  z-index: 1000;
  padding: 16px;                  /* breathing room on small screens */
}

/* The dialog itself: capped height, internal scroll when content overflows. */
.modal {
  box-sizing: border-box;
  width: min(560px, 100%);        /* responsive max width */
  max-height: 90vh;
  overflow-y: auto;               /* scroll inside, not the whole page */
  background: #fff;
  border-radius: 12px;
  padding: 24px;
}
